"use client";

import { useState, useEffect, useRef } from "react";
import { motion } from "framer-motion";
import { ArrowUpRight, Search } from "lucide-react";


// ----------------------------------------------------------------
// BLOG DATA
// ----------------------------------------------------------------

const POSTS = [
  {
    title: "Why Scaling Microservices is Harder Than You Think",
    date: "Feb 24, 2026",
    readTime: "6 min read",
    description:
      "Discussing common pitfalls in distributed systems including split-brain and network partitions.",
    tags: ["architecture", "backend", "cloud"],
  },
  {
    title: "Optimizing DynamoDB for High-Throughput Workloads",
    date: "Jan 12, 2026",
    readTime: "8 min read",
    description:
      "Deep dive into partition keys, GSI overloading and hot partition mitigation.",
    tags: ["database", "aws", "backend"],
  },
];

const TAGS = ["All", ...Array.from(new Set(POSTS.flatMap(p => p.tags)))];

// ----------------------------------------------------------------
// BLOG CARD
// ----------------------------------------------------------------

function BlogCard({ post }: { post: any }) {
  return (
    <motion.div
      initial={{ opacity: 0, y: 24 }}
      animate={{ opacity: 1, y: 0 }}
      className="group rounded-2xl border border-neutral-200 dark:border-white/10
      bg-white/70 dark:bg-white/5 backdrop-blur-md p-7 flex flex-col justify-between
      hover:bg-neutral-50 dark:hover:bg-white/10 transition-all duration-300"
    >
      <div className="flex items-center justify-between mb-5">
        <div className="text-xs text-neutral-500 flex gap-2 uppercase tracking-wide">
          <span>{post.date}</span>
          <span>•</span>
          <span>{post.readTime}</span>
        </div>

        <div className="w-8 h-8 flex items-center justify-center rounded-full
        border border-neutral-300 dark:border-white/15
        group-hover:border-neutral-900 dark:group-hover:border-white
        transition">
          <ArrowUpRight size={14} />
        </div>
      </div>

      <div>
        <h3 className="text-lg font-bold mb-2 text-neutral-900 dark:text-white">
          {post.title}
        </h3>

        <p className="text-sm text-neutral-500 dark:text-neutral-400">
          {post.description}
        </p>
      </div>

      <div className="flex flex-wrap gap-2 mt-6">
        {post.tags.map((tag: string) => (
          <span
            key={tag}
            className="px-3 py-1 rounded-full text-[10px]
            border border-neutral-200 dark:border-white/10
            bg-neutral-100 dark:bg-white/5 text-neutral-500"
          >
            {tag}
          </span>
        ))}
      </div>
    </motion.div>
  );
}

// ----------------------------------------------------------------
// ACHIEVEMENT DATA
// ----------------------------------------------------------------

const PLATFORMS = [
  {
    name: "LeetCode",
    url: "https://leetcode.com/",
    color: "#FFA116",
    stats: ["300+ problems solved", "Top 25%"],
  },
  {
    name: "HackerRank",
    url: "https://hackerrank.com/",
    color: "#00EA64",
    stats: ["5★ Problem Solving", "4★ C++"],
  },
  {
    name: "CodeChef",
    url: "https://codechef.com/",
    color: "#e8845e",
    stats: ["Rating 1600+", "Div 2"],
  },
  {
    name: "Codeforces",
    url: "https://codeforces.com/",
    color: "#1F8ACB",
    stats: ["Max Rating 1400+", "Specialist"],
  },
];

// ----------------------------------------------------------------
// ACHIEVEMENT CARD
// ----------------------------------------------------------------

function PlatformCard({ platform }: any) {
  return (
    <motion.div
      whileHover={{
        y: -6,
        boxShadow: `0 20px 40px ${platform.color}33, 0 0 30px ${platform.color}22`,
      }}
      className="group rounded-2xl border border-neutral-200 dark:border-white/10
      bg-white/70 dark:bg-white/5 backdrop-blur-md p-6 flex flex-col
      transition-all duration-300"
    >
      <h3 className="font-bold text-lg mb-1">{platform.name}</h3>

      <ul className="text-sm text-neutral-500 dark:text-neutral-400 mb-6">
        {platform.stats.map((s: string) => (
          <li key={s}>• {s}</li>
        ))}
      </ul>

      <a
        href={platform.url}
        target="_blank"
        rel="noopener noreferrer"
        style={{ "--clr": platform.color } as any}
        className="mt-auto text-sm font-semibold
        border rounded-lg px-4 py-2 flex items-center justify-center gap-2
        transition-all duration-300
        border-[var(--clr)] text-[var(--clr)]
        hover:bg-[var(--clr)] hover:text-white
        hover:shadow-[0_0_20px_var(--clr)]"
      >
        View Profile
      </a>
    </motion.div>
  );
}

// ----------------------------------------------------------------
// MAIN BLOG
// ----------------------------------------------------------------

export function Blog() {
  const [search, setSearch] = useState("");
  const [tag, setTag] = useState("All");

  const filtered = POSTS.filter(post => {
    const matchTag = tag === "All" || post.tags.includes(tag);
    const matchSearch =
      post.title.toLowerCase().includes(search.toLowerCase()) ||
      post.description.toLowerCase().includes(search.toLowerCase());
    return matchTag && matchSearch;
  });

  return (
    <div className="max-w-[1400px] mx-auto px-6 py-24">

      {/* TITLE */}
      <div className="text-center mb-16">
        <h1 className="text-6xl font-black">BLOGS</h1>
        <p className="text-neutral-500 mt-4">
          Thoughts, tutorials and insights I share.
        </p>
      </div>

      {/* SEARCH */}
      <div className="flex items-center gap-3 mb-10 max-w-md">
        <Search size={16} />
        <input
          placeholder="Search..."
          className="flex-1 outline-none bg-transparent"
          value={search}
          onChange={e => setSearch(e.target.value)}
        />
      </div>

      {/* BLOG GRID */}
      <div className="grid md:grid-cols-2 lg:grid-cols-3 gap-6 mb-28">
        {filtered.map((p, i) => (
          <BlogCard key={i} post={p} />
        ))}
      </div>

      {/* ACHIEVEMENTS */}
      <section>
        <h2 className="text-5xl font-black text-center mb-14">
          Competitive Programming
        </h2>

        <div className="grid md:grid-cols-2 lg:grid-cols-4 gap-6">
          {PLATFORMS.map(p => (
            <PlatformCard key={p.name} platform={p} />
          ))}
        </div>
      </section>
    </div>
  );
}